def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve dict-based dynamic defaults now that every parameter
    has been parsed.

    A dynamic default maps another option's declaration name (e.g.
    ``"--protocol"``) to a ``{stringified value: default}`` mapping.
    It only overrides an option's value when that option's value
    source is still :attr:`ParameterSource.DEFAULT`. If multiple
    source options are given, later entries take precedence. If
    nothing matches, the option is left as ``None``.
    """
    params = self.get_params(ctx)
    opt_lookup: dict[str, Parameter] = {}

    for param in params:
        for opt in (*param.opts, *param.secondary_opts):
            opt_lookup[opt] = param

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for source_opt, mapping in param.default.items():
            source_param = opt_lookup.get(source_opt)

            if source_param is None:
                continue

            source_value = ctx.params.get(source_param.name)
            key = str(source_value)

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            ctx.params[param.name] = param.type_cast_value(ctx, resolved)  # type: ignore[arg-type]

